function selectMustCover(lessons, slotCount) {
  if (!lessons || lessons.length === 0) {
    return { mustCover: [], discarded: [] };
  }

  const sorted = [...lessons].sort((a, b) => {
    if (b.Priority_Ranking !== a.Priority_Ranking) {
      return b.Priority_Ranking - a.Priority_Ranking;
    }
    return a.Lesson_Sequence - b.Lesson_Sequence;
  });

  const mustCover = sorted.slice(0, slotCount);
  const discarded = sorted.slice(slotCount);

  console.log(`  selectMustCover: ${lessons.length} lessons, ${slotCount} slots → ${mustCover.length} must, ${discarded.length} discarded`);
  return { mustCover, discarded };
}

