function distributeToWeeks(mustCoverLessons, discardedLessons, weekNumbers, mustCoversPerWeek) {
  if (!weekNumbers || weekNumbers.length === 0) return { schedule: [], droppedCount: 0, uncoveredLessons: new Set(), uncoveredUnits: new Set() };

