  const allLessonsByLessonNum = {};
  [...mustCoverLessons, ...discardedLessons].forEach(lesson => {
    const key = extractLessonNumber(lesson.Lesson_Title || '');
    if (key) {
      if (!allLessonsByLessonNum[key]) allLessonsByLessonNum[key] = [];
      allLessonsByLessonNum[key].push(lesson);
    }
  });
  Object.values(allLessonsByLessonNum).forEach(arr =>
    arr.sort((a, b) => a.Lesson_Sequence - b.Lesson_Sequence)
  );

  // Index discarded lessons by X.Y lesson number
  const discardedByLessonNum = {};
  discardedLessons.forEach(lesson => {
    const key = extractLessonNumber(lesson.Lesson_Title || '');
    if (key) {
      if (!discardedByLessonNum[key]) discardedByLessonNum[key] = [];
      discardedByLessonNum[key].push(lesson);
    }
  });

  const weeklySchedule = [];
  const weekByNumber = {};
  let mustIndex = 0;
  const usedDiscardedIds = new Set();
  const placedMustSequences = new Set();
  const lessonNumToWeekNum = {};

  for (const weekNum of weekNumbers) {
    const weekMustCover = [];
    for (let j = 0; j < mustCoversPerWeek && mustIndex < mustQueue.length; j++) {
      const lesson = mustQueue[mustIndex];
      weekMustCover.push(lesson);

      const lNum = extractLessonNumber(lesson.Lesson_Title || '');
      if (lNum && !lessonNumToWeekNum[lNum]) {
        lessonNumToWeekNum[lNum] = weekNum;
      }

      mustIndex++;
    }

    if (weekMustCover.length === 0) continue;

    const thisWeekMustSeqs = new Set(weekMustCover.map(l => l.Lesson_Sequence));
    const allPlacedSoFar = new Set([...placedMustSequences, ...thisWeekMustSeqs]);

    const lessonNumsThisWeek = new Set(
      weekMustCover.map(l => extractLessonNumber(l.Lesson_Title || ''))
    );

    function isEligible(candidate) {
      const key = extractLessonNumber(candidate.Lesson_Title || '');
      const candidateSeq = candidate.Lesson_Sequence;
      const group = allLessonsByLessonNum[key] || [];

      for (const lesson of group) {
        if (lesson.Lesson_Sequence >= candidateSeq) break;
        if (!allPlacedSoFar.has(lesson.Lesson_Sequence)) {
          return false;
        }
      }
      return true;
    }

    const eligibleDiscarded = [];
    lessonNumsThisWeek.forEach(lessonNum => {
      (discardedByLessonNum[lessonNum] || []).forEach(lesson => {
        if (!usedDiscardedIds.has(lesson.id) && isEligible(lesson)) {
          eligibleDiscarded.push(lesson);
        }
      });
    });

    eligibleDiscarded.sort((a, b) => {
      if (b.Priority_Ranking !== a.Priority_Ranking) return b.Priority_Ranking - a.Priority_Ranking;
      return a.Lesson_Sequence - b.Lesson_Sequence;
    });

    const couldCover = [];
    const skip = [];

    if (eligibleDiscarded.length > 0) {
      const topPriority = eligibleDiscarded[0].Priority_Ranking;
      eligibleDiscarded.forEach(lesson => {
        if (lesson.Priority_Ranking === topPriority) {
          couldCover.push(lesson);
        } else {
          skip.push(lesson);
        }
        usedDiscardedIds.add(lesson.id);
      });
    }

    thisWeekMustSeqs.forEach(seq => placedMustSequences.add(seq));

    const allLessonsThisWeek = [
      ...weekMustCover.map(l => normalize(l, 'must-cover')),
      ...couldCover.map(l => normalize(l, 'could-cover')),
      ...skip.map(l => normalize(l, 'can-skip'))
    ];

    const weekObj = {
      weekNumber   : weekNum,
      lessons      : allLessonsThisWeek,
      totalMinutes : weekMustCover.length * AVG_MINUTES_PER_SESSION
    };

    weeklySchedule.push(weekObj);
    weekByNumber[weekNum] = weekObj;
  }

  // ── Distribute remaining discarded ──
  // Only attach if exact X.Y had must-covers; otherwise drop
  const uncoveredLessons = new Set();
  const uncoveredUnits = new Set();
  let droppedCount = 0;

  discardedLessons.forEach(lesson => {
    if (usedDiscardedIds.has(lesson.id)) return;

    const lNum = extractLessonNumber(lesson.Lesson_Title || '');

    if (lNum && lessonNumToWeekNum[lNum] && weekByNumber[lessonNumToWeekNum[lNum]]) {
      const targetWeek = weekByNumber[lessonNumToWeekNum[lNum]];
      targetWeek.lessons.push(normalize(lesson, 'can-skip'));
      usedDiscardedIds.add(lesson.id);
    } else {
      // DROP
      uncoveredLessons.add(`${lNum}: ${(lesson.Lesson_Title || '').replace(/Day \d+\s*/i, '').trim()}`);
      uncoveredUnits.add(lesson.Unit_Name || '');
      droppedCount++;
      usedDiscardedIds.add(lesson.id);
    }
  });

  return { schedule: weeklySchedule, droppedCount, uncoveredLessons, uncoveredUnits };
}

