      const plural = lesson.canSkipDays.length > 1 ? "days" : "day";
      canSkipLessons.push(`Lesson ${lesson.lessonNumber}: ${lesson.lessonName} (${plural} ${days})`);
    }
  });

  weeks.push({
    weekNumber: weekNum,
    weekTitle: "",
    module: moduleName,
    type: "regular",
    mustCover: mustCoverLessons.join("\n"),
    couldCover: couldCoverLessons.join("\n"),
    skip: canSkipLessons.join("\n")
  });
}

