  const allContent = [week.mustCover, week.couldCover, week.skip];

  allContent.forEach((content, idx) => {
    if (!content) return;
    const lines = content.split('\n').filter(line => line.trim());
    lines.forEach(line => {
      const dayMatch = line.match(/\(days? ([\d,\s]+)\)/);
      if (dayMatch) {
        const days = dayMatch[1].split(',').map(d => d.trim()).filter(Boolean);
        if (idx === 0) mustCoverDayCount += days.length;
        else if (idx === 1) couldCoverDayCount += days.length;
        else skipDayCount += days.length;
      } else if (line.trim() === "Final Pitch") {
        // Final Pitch is 1 must-cover day
        if (idx === 0) mustCoverDayCount += 1;
      }
    });
  });
});

