const selectedCertifications = validateNode.certifications ?? [];
const hasESBCert = selectedCertifications.includes(esbCertification);

// --- Skipped modules (clone only once) ---
const skippedModules = Array.isArray(calcNode.skippedModules)
  ? [...calcNode.skippedModules]
  : [];

// --- Maps ---
const lessonsMap = Object.create(null);
const modulesMap = Object.create(null);

// --- Build lessons & modules ---
for (const row of supabaseRows) {
  const moduleNumber = Number(row.Module_Number);
  const lessonNumber = Number(row.Lesson_Number);
  const dayNumber = Number(row.Day_Number);

  if (!modulesMap[moduleNumber]) {
    let isSkipped = skippedModules.includes(row.Module_Name);

    // ESB rule
    if (moduleNumber === esbModuleNumber && !hasESBCert) {
      isSkipped = true;
      if (!skippedModules.includes(esbModuleName)) {
        skippedModules.push(esbModuleName);
      }
    }

    modulesMap[moduleNumber] = {
      moduleNumber,
      moduleName: row.Module_Name,
      certification: row.Certification_Association ?? null,
      lessons: [],
      skipped: isSkipped
    };
  }

  if (modulesMap[moduleNumber].skipped) continue;

  const lessonKey = `${moduleNumber}.${lessonNumber}`;

  if (!lessonsMap[lessonKey]) {
    lessonsMap[lessonKey] = {
      lessonId: lessonKey,
      moduleNumber,
      moduleName: row.Module_Name,
      lessonNumber,
      lessonTitle: (row.Lesson_Title || "").replace(": CIP", "").trim(),
      certification: row.Certification_Association ?? null,
      days: [],
      skipped: false
    };
  }

  // Read numerical Priority_Ranking (1-5, where 5 = highest)
  const priorityRanking = Number(row.Priority_Ranking) || 1;

  lessonsMap[lessonKey].days.push({
    day: dayNumber,
    priorityRanking: priorityRanking,
    dayTitle: row.Day_Title,
    notes: row.Notes,
    estimatedMinutes:
      Number.parseInt(row["Estimated Length"], 10) || avgMinutesPerSession
  });
}

// --- Attach lessons to modules ---
for (const lesson of Object.values(lessonsMap)) {
  const mod = modulesMap[lesson.moduleNumber];
  if (mod && !mod.skipped) {
    mod.lessons.push(lesson);
  }
}

// --- Ensure ESB module exists ---
if (!modulesMap[esbModuleNumber]) {
  modulesMap[esbModuleNumber] = {
    moduleNumber: esbModuleNumber,
    moduleName: esbModuleName,
    certification: esbCertification,
    lessons: [],
    skipped: !hasESBCert
  };

  if (!hasESBCert && !skippedModules.includes(esbModuleName)) {
    skippedModules.push(esbModuleName);
  }
}

