  lesson.days.forEach(day => {
    let finalPriorityRanking = day.priorityRanking;
    let isCertificationLocked = false;
    let isCertificationOptional = false;

    // CRITICAL: Certification modules Days 1-4 are ALWAYS highest priority
    if (moduleHasCert && day.day >= 1 && day.day <= 4) {
      finalPriorityRanking = 5; // Max priority
      isCertificationLocked = true;
      console.log(`Cert Override: Module ${lesson.moduleNumber}, Lesson ${lesson.lessonNumber}, Day ${day.day} → Priority 5 (LOCKED)`);
    } else if (moduleHasCert && day.day === 5) {
      // Day 5 of certification modules is optional
      isCertificationOptional = true;
      console.log(`Cert Override: Module ${lesson.moduleNumber}, Lesson ${lesson.lessonNumber}, Day ${day.day} → Could Cover (optional)`);
    }

    data.selectedLessons.push({
      lessonId: lesson.lessonId,
      lessonNumber: lesson.lessonNumber,
      day: day.day,
      lessonTitle: lesson.lessonTitle,
      moduleNumber: lesson.moduleNumber,
      moduleName: lesson.moduleName,
      certification: lesson.certification,
      priorityRanking: finalPriorityRanking,
      isCertificationLocked: isCertificationLocked,
      isCertificationOptional: isCertificationOptional,
      estimatedMinutes: avgMinutesPerSession
    });
  });
});

// === COURSE CONNECTIONS OVERRIDE ===
// If teacher is NOT integrating Course Connections, demote ALL Day 5 lessons to lowest priority
const includeCourseConnections = data.includeCourseConnections || false;

if (!includeCourseConnections) {
  let day5OverrideCount = 0;
  data.selectedLessons.forEach(lesson => {
    if (lesson.day === 5 && !lesson.isCertificationLocked) {
      lesson.priorityRanking = 0;
      day5OverrideCount++;
    }
  });
  console.log(`\nCourse Connections: OFF — Demoted ${day5OverrideCount} Day 5 lessons to priority 1`);
} else {
  console.log(`\nCourse Connections: ON — Day 5 priorities unchanged`);
}

// Calculate statistics
const certLockedCount = data.selectedLessons.filter(l => l.isCertificationLocked).length;
const certOptionalCount = data.selectedLessons.filter(l => l.isCertificationOptional).length;
console.log(`\nTotal selected lessons: ${data.selectedLessons.length}`);
console.log(`Certification locked: ${certLockedCount}`);
console.log(`Certification optional: ${certOptionalCount}`);
console.log(`========================================`);

return {
  json: {
    ...data,
    certificationsApplied: certifications.length > 0
  }
};
